coration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.cs-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.cs-cta-btn:hover::before{left:100%}\n.cs-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.cs-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.cs-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.cs-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.cs-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.cs-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .cs-cta-title{font-size:28px;margin-bottom:16px}\n  .cs-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .cs-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .cs-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.cs-cta-btn{transition:none !important}.cs-cta-btn::before{display:none}}\n/* Case-studies-specific overrides to match HTML prototype */\n.et_pb_section .cs-cta-title{font-weight:800 !important}\n.cs-cta-section::before{background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.05\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E") !important}\n.cs-cta-section::after{display:none !important}\n.cs-cta-subtitle{color:rgba(255,255,255,0.85) !important}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-hero">\n    <div class="cs-hero-inner">\n                <div class="cs-hero-badge" aria-hidden="true">Case Studies</div>\n                <h1>Real Factories. Real Results.</h1>\n                <p class="cs-hero-subtitle">Thai manufacturers share how DigiWin transformed their operations — with measurable outcomes, not marketing promises.</p>\n                <div class="cs-hero-stats" role="list" aria-label="Key statistics">\n                    <div role="listitem">\n                        <div class="cs-hero-stat-value">5</div>\n                        <div class="cs-hero-stat-label">Detailed Case Studies</div>\n                    </div>\n                    <div role="listitem">\n                        <div class="cs-hero-stat-value">3</div>\n                        <div class="cs-hero-stat-label">Industries</div>\n                    </div>\n                    <div role="listitem">\n                        <div class="cs-hero-stat-value">75%</div>\n                        <div class="cs-hero-stat-label">Avg. Closing Time Cut</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Grid"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Grid: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Grid: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-grid-section">\n    <div class="cs-grid-inner">\n    \n                \n                <div class="cs-filters" role="group" aria-label="Filter by industry">\n                    <button class="cs-filter-btn active" aria-pressed="true" data-filter="all">All</button>\n                    <button class="cs-filter-btn" aria-pressed="false" data-filter="plastics-packaging">Plastics &amp; Packaging</button>\n                    <button class="cs-filter-btn" aria-pressed="false" data-filter="metal-precision">Metal &amp; Precision</button>\n                    <button class="cs-filter-btn" aria-pressed="false" data-filter="electronics">Electronics</button>\n                    <button class="cs-filter-btn" aria-pressed="false" data-filter="fasteners">Fasteners &amp; Components</button>\n                </div>\n    \n                \n                <div class="cs-card-grid">\n    \n                    \n                    <a href="#case-ginfong" class="cs-card cs-animate" data-industry="metal-precision" aria-label="Ginfong Precision case study">\n                        <div class="cs-card-badge">Metal Stamping</div>\n                        <h2 class="cs-card-company">Ginfong Precision</h2>\n                        <p class="cs-card-summary">Metal stamping manufacturer that grew revenue 200% through COVID with cost visibility.</p>\n                        <div class="cs-card-metric">+200%</div>\n                        <div class="cs-card-metric-label">Revenue Growth</div>\n                        <div class="cs-card-products">\n                            <span class="cs-card-product-tag">ERP</span>\n                            <span class="cs-card-product-tag">SFT</span>\n                        </div>\n                        <span class="cs-card-link">Read Case Study</span>\n                    </a>\n    \n                    \n                    <a href="#case-thai-alpha" class="cs-card cs-animate" data-industry="plastics-packaging" aria-label="Thai Alpha Polymer case study">\n                        <div class="cs-card-badge">Plastics Manufacturing</div>\n                        <h2 class="cs-card-company">Thai Alpha Polymer</h2>\n                        <p class="cs-card-summary">PET plastic manufacturer that slashed month-end closing from 60 to 15 days.</p>\n                        <div class="cs-card-metric">60→15</div>\n                        <div class="cs-card-metric-label">Days to Close</div>\n                        <div class="cs-card-products">\n                            <span class="cs-card-product-tag">iGP ERP</span>\n                            <span class="cs-card-product-tag">WMS</span>\n                        </div>\n                        <span class="cs-card-link">Read Case Study</span>\n                    </a>\n    \n                    \n                    <a href="#case-thai-hosheng" class="cs-card cs-animate" data-industry="plastics-packaging" aria-label="Thai Hosheng Packing case study">\n                        <div class="cs-card-badge">Packaging</div>\n                        <h2 class="cs-card-company">Thai Hosheng Packing</h2>\n                        <p class="cs-card-summary">Packaging manufacturer with the most dramatic closing reduction — 90 days down to 15.</p>\n                        <div class="cs-card-metric">90→15</div>\n                        <div class="cs-card-metric-label">Days to Close</div>\n                        <div class="cs-card-products">\n                            <span class="cs-card-product-tag">iGP ERP</span>\n                            <span class="cs-card-product-tag">WMS</span>\n                            <span class="cs-card-product-tag">SFT</span>\n                        </div>\n                        <span class="cs-card-link">Read Case Study</span>\n                    </a>\n    \n                    \n                    <a href="#case-mufu" class="cs-card cs-animate" data-industry="electronics" aria-label="MUFU Technologies case study">\n                        <div class="cs-card-badge">Manufacturing</div>\n                        <h2 class="cs-card-company">MUFU Technologies</h2>\n                        <p class="cs-card-summary">Manufacturing company that unified all departments into one automated system.</p>\n                        <div class="cs-card-metric" style="font-size: 1.5rem;">Unified Ops</div>\n                        <div class="cs-card-metric-label">Full Automation Achieved</div>\n                        <div class="cs-card-products">\n                            <span class="cs-card-product-tag">iGP ERP</span>\n                        </div>\n                        <span class="cs-card-link">Read Case Study</span>\n                    </a>\n    \n                    \n                    <a href="#case-taiyo" class="cs-card cs-animate" data-industry="fasteners" aria-label="Taiyo Fastener Thailand case study">\n                        <div class="cs-card-badge">Fasteners</div>\n                        <h2 class="cs-card-company">Taiyo Fastener Thailand</h2>\n                        <p class="cs-card-summary">Japanese-standard fastener manufacturer that unified fragmented legacy systems.</p>\n                        <div class="cs-card-metric" style="font-size: 1.5rem;">Systems Unified</div>\n                        <div class="cs-card-metric-label">Multiple Systems → One Platform</div>\n                        <div class="cs-card-products">\n                            <span class="cs-card-product-tag">ERP</span>\n                            <span class="cs-card-product-tag">WMS</span>\n                        </div>\n                        <span class="cs-card-link">Read Case Study</span>\n                    </a>\n    \n                </div>\n            </div>\n    </div>\n    <script>\n    (function(){\n      var filterBtns = document.querySelectorAll(\'.cs-filter-btn\');\n      var cards = document.querySelectorAll(\'.cs-card\');\n      filterBtns.forEach(function(btn){\n        btn.addEventListener(\'click\', function(){\n          var filter = this.getAttribute(\'data-filter\');\n          filterBtns.forEach(function(b){\n            b.classList.remove(\'active\');\n            b.setAttribute(\'aria-pressed\',\'false\');\n          });\n          this.classList.add(\'active\');\n          this.setAttribute(\'aria-pressed\',\'true\');\n          cards.forEach(function(card){\n            if(filter===\'all\'||card.getAttribute(\'data-industry\')===filter){\n              card.style.display=\'\';\n            }else{\n              card.style.display=\'none\';\n            }\n          });\n        });\n      });\n      function smoothScrollTo(el, duration){\n        var start = window.pageYOffset;\n        var end = el.getBoundingClientRect().top + start;\n        var dist = end - start;\n        var startTime = null;\n        function step(ts){\n          if(!startTime) startTime = ts;\n          var t = Math.min((ts - startTime) / duration, 1);\n          var ease = t < 0.5 ? 2*t*t : -1+(4-2*t)*t;\n          window.scrollTo(0, start + dist * ease);\n          if(t < 1) requestAnimationFrame(step);\n        }\n        requestAnimationFrame(step);\n      }\n      document.querySelectorAll(\'.cs-card\').forEach(function(card){\n        card.addEventListener(\'click\', function(e){\n          var href = this.getAttribute(\'href\');\n          if(href && href.startsWith(\'#\')){\n            e.preventDefault();\n            var target = document.querySelector(href);\n            if(target) smoothScrollTo(target, 800);\n          }\n        });\n      });\n    })();\n    </script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-detail-section" id="case-ginfong" style="background:#F5F7FA">\n    <div class="cs-detail-inner">\n                <div class="cs-detail-header cs-animate">\n                    <div class="cs-detail-badge">Metal Stamping</div>\n                    <div class="cs-company-identity">\n                        <div class="cs-company-logo">\n                            <img src="data:image/png;base64," alt="Ginfong Precision logo" loading="lazy">\n                        </div>\n                        <div class="cs-company-info-block">\n                            <h2 class="cs-detail-company">Ginfong Precision <span style="font-weight: 400; font-size: 0.6em; color: #666;">(金峰精密)</span></h2>\n                            <p class="cs-company-desc">Metal stamping manufacturer · Thailand</p>\n                        </div>\n                    </div>\n                    <div class="cs-detail-products-used">\n                        <span class="cs-detail-product-tag">ERP</span>\n                        <span class="cs-detail-product-tag">SFT</span>\n                    </div>\n                    <div class="cs-detail-metric-hero">\n                        <span class="cs-detail-metric-value">+200%</span>\n                        <span class="cs-detail-metric-desc">Revenue Growth</span>\n                    </div>\n                </div>\n    \n                <h3>The Challenge</h3>\n                <p>Metal stamping manufacturer struggling with cost visibility and production tracking. Manual processes couldn\'t keep pace with growing order volumes. No real-time view of actual production costs vs. quoted costs.</p>\n    \n                <h3>The Solution</h3>\n                <p>Deployed DigiWin ERP for financial control and cost tracking, plus SFT (Shop Floor Tracking) for real-time production data collection. The combination gave management live visibility into actual costs at each production stage.</p>\n    \n                <h3>Results</h3>\n                <table class="cs-results-table cs-animate" aria-label="Ginfong results">\n                    <thead>\n                        <tr>\n                            <th scope="col">Metric</th>\n                            <th scope="col">Before</th>\n                            <th scope="col">After</th>\n                            <th scope="col">Change</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td>Gross profit margin</td>\n                            <td>23%</td>\n                            <td>34%</td>\n                            <td class="cs-change-positive">+11 percentage points</td>\n                        </tr>\n                        <tr>\n                            <td>Revenue</td>\n                            <td>Baseline</td>\n                            <td>+200%</td>\n                            <td class="cs-change-positive">Grew through COVID</td>\n                        </tr>\n                    </tbody>\n                </table>\n    \n                <h3>Why It Matters</h3>\n                <p>Ginfong didn\'t just survive COVID — they grew revenue by 200% while competitors contracted. The gross profit improvement from 23% to 34% proves DigiWin\'s cost visibility directly translates to better pricing decisions and waste reduction.</p>\n    \n                \n                <a href="https://www.youtube.com/watch?v=p5vn_llRe5M" target="_blank" rel="noopener noreferrer" class="cs-video-link">\n                    <div class="cs-video-icon">\n                        <svg viewBox="0 0 24 24" aria-hidden="true"><polygon points="10,8 16,12 10,16"/></svg>\n                    </div>\n                    <div>\n                        <div class="cs-video-text">Watch Ginfong\'s Story on YouTube</div>\n                        <div style="font-size: 0.75rem; color: #666;">Opens in new tab</div>\n                    </div>\n                </a>\n    \n                \n                <div class="cs-callout cs-animate">\n                    <div class="cs-callout-title">What Ginfong Looked For in an ERP Partner</div>\n                    <p>Ginfong evaluated vendors on 7 criteria — does your checklist look similar?</p>\n                    <ul class="cs-criteria-list">\n                        <li>After-sales service quality</li>\n                        <li>Thai tax compliance</li>\n                        <li>Market share and reputation</li>\n                        <li>Industry-specific experience</li>\n                        <li>Brand longevity</li>\n                        <li>Price-to-value ratio</li>\n                        <li>Multilingual support</li>\n                    </ul>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 2"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 2: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 2: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-detail-section" id="case-thai-alpha" style="background:#fff">\n    <div class="cs-detail-inner">\n                <div class="cs-detail-header cs-animate">\n                    <div class="cs-detail-badge">Plastics Manufacturing</div>\n                    <div class="cs-company-identity">\n                        <div class="cs-company-logo">\n                            <img src="data:image/png;base64," alt="Thai Alpha Polymer logo" loading="lazy">\n                        </div>\n                        <div class="cs-company-info-block">\n                            <h2 class="cs-detail-company">Thai Alpha Polymer</h2>\n                            <p class="cs-company-desc">PET plastic roll manufacturer · Thailand</p>\n                        </div>\n                    </div>\n                    <div class="cs-detail-products-used">\n                        <span class="cs-detail-product-tag">Workflow ERP (iGP)</span>\n                        <span class="cs-detail-product-tag">WMS (sFLS)</span>\n                    </div>\n                    <div class="cs-detail-metric-hero">\n                        <span class="cs-detail-metric-value">60→15</span>\n                        <span class="cs-detail-metric-desc">Days to Close</span>\n                    </div>\n                </div>\n    \n                <h3>The Challenge</h3>\n                <p>PET plastic roll manufacturer with inventory accuracy problems and painfully slow month-end closing. Physical counts never matched system records. Finance team spent weeks reconciling.</p>\n    \n                <h3>The Solution</h3>\n                <p>Deployed DigiWin Workflow ERP for financial management and WMS (sFLS) for barcode-driven warehouse operations. Every material movement now captured at source via scanning.</p>\n    \n                <h3>Results</h3>\n                <table class="cs-results-table cs-animate" aria-label="Thai Alpha Polymer results">\n                    <thead>\n                        <tr>\n                            <th scope="col">Metric</th>\n                            <th scope="col">Before</th>\n                            <th scope="col">After</th>\n                            <th scope="col">Change</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td>Stock accuracy</td>\n                            <td>Unknown</td>\n                            <td>95%</td>\n                            <td class="cs-change-positive">Barcode-driven accuracy</td>\n                        </tr>\n                        <tr>\n                            <td>Monthly closing</td>\n                            <td>60 days</td>\n                            <td>15 days</td>\n                            <td class="cs-change-positive">75% faster</td>\n                        </tr>\n                    </tbody>\n                </table>\n    \n                \n                <h3>From the Team</h3>\n                <blockquote class="cs-quote cs-animate">\n                    <p>"The closing process used to take our entire team two months. Now we\'re done in two weeks."</p>\n                    <cite>— Khun Noo, Accounting Department</cite>\n                </blockquote>\n                <blockquote class="cs-quote cs-animate">\n                    <p>"Every scan updates the system instantly. We finally trust our inventory numbers."</p>\n                    <cite>— Khun Ae, Warehouse</cite>\n                </blockquote>\n    \n                \n                <div class="cs-callout cs-animate">\n                    <div class="cs-callout-title">Recommended by a Fellow Manufacturer</div>\n                    <p>Thai Alpha chose DigiWin based on a recommendation from Thai Hosheng — a fellow manufacturer already running on our system. The strongest form of social proof is when a customer stakes their own reputation on your work.</p>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 3"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 3: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 3: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-detail-section" id="case-thai-hosheng" style="background:#F5F7FA">\n    <div class="cs-detail-inner">\n                <div class="cs-detail-header cs-animate">\n                    <div class="cs-detail-badge">Packaging</div>\n                    <div class="cs-company-identity">\n                        <div class="cs-company-logo">\n                            <img src="data:image/png;base64," alt="Thai Hosheng Packing logo" loading="lazy">\n                        </div>\n                        <div class="cs-company-info-block">\n                            <h2 class="cs-detail-company">Thai Hosheng Packing</h2>\n                            <p class="cs-company-desc">Packaging manufacturer · Thailand</p>\n                        </div>\n                    </div>\n                    <div class="cs-detail-products-used">\n                        <span class="cs-detail-product-tag">Workflow ERP (iGP)</span>\n                        <span class="cs-detail-product-tag">WMS (sFLS)</span>\n                        <span class="cs-detail-product-tag">SFT</span>\n                    </div>\n                    <div class="cs-detail-metric-hero">\n                        <span class="cs-detail-metric-value">90→15</span>\n                        <span class="cs-detail-metric-desc">Days to Close</span>\n                    </div>\n                </div>\n    \n                <h3>The Challenge</h3>\n                <p>Packaging manufacturer with the worst closing time in our case study portfolio — 90 days. Combined with low stock accuracy and unreliable on-time delivery. The business was growing but operations couldn\'t keep up.</p>\n    \n                <h3>The Solution</h3>\n                <p>Full DigiWin stack deployment: Workflow ERP for financials, WMS for warehouse accuracy, and SFT for shop floor tracking. Three systems working as one integrated operation.</p>\n    \n                <h3>Results</h3>\n                <table class="cs-results-table cs-animate" aria-label="Thai Hosheng results">\n                    <thead>\n                        <tr>\n                            <th scope="col">Metric</th>\n                            <th scope="col">Before</th>\n                            <th scope="col">After</th>\n                            <th scope="col">Change</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td>Monthly closing</td>\n                            <td>90 days</td>\n                            <td>15 days</td>\n                            <td class="cs-change-positive">83% faster</td>\n                        </tr>\n                        <tr>\n                            <td>Stock accuracy</td>\n                            <td>Unknown</td>\n                            <td>90%</td>\n                            <td class="cs-change-positive">System-matched inventory</td>\n                        </tr>\n                        <tr>\n                            <td>On-time delivery</td>\n                            <td>Unknown</td>\n                            <td>80%</td>\n                            <td class="cs-change-positive">Measurable OTD tracking</td>\n                        </tr>\n                    </tbody>\n                </table>\n    \n                <h3>Why It Matters</h3>\n                <p>Thai Hosheng is the most comprehensive deployment in our case study portfolio — ERP + WMS + SFT together. The 90-to-15-day closing improvement is the most dramatic transformation. They also referred Thai Alpha to DigiWin, proving satisfaction strong enough to stake their own reputation on.</p>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 4"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 4: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 4: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-detail-section" id="case-mufu" style="background:#fff">\n    <div class="cs-detail-inner">\n                <div class="cs-detail-header cs-animate">\n                    <div class="cs-detail-badge">Manufacturing</div>\n                    <div class="cs-company-identity">\n                        <div class="cs-company-logo">\n                            <img src="data:image/png;base64," alt="MUFU Technologies logo" loading="lazy">\n                        </div>\n                        <div class="cs-company-info-block">\n                            <h2 class="cs-detail-company">MUFU Technologies</h2>\n                            <p class="cs-company-desc">Manufacturing technology · Taiwan</p>\n                        </div>\n                    </div>\n                    <div class="cs-detail-products-used">\n                        <span class="cs-detail-product-tag">Workflow ERP (iGP)</span>\n                    </div>\n                    <div class="cs-detail-metric-hero">\n                        <span class="cs-detail-metric-value" style="font-size: 2rem;">Full Automation</span>\n                    </div>\n                </div>\n    \n                <h3>The Challenge</h3>\n                <p>Manufacturing company with manual, disconnected processes across departments. Information silos meant no single view of operations. Each department had its own spreadsheets, its own version of the truth.</p>\n    \n                <h3>The Solution</h3>\n                <p>Deployed DigiWin Workflow ERP to unify all departments — purchasing, production, inventory, and finance — into a single system. One source of truth, one workflow, one set of numbers.</p>\n    \n                <h3>Results</h3>\n                <ul style="padding-left: 0; list-style: none;">\n                    <li style="padding: 10px 0; border-bottom: 1px solid #e2e8f0; color: #333; display: flex; align-items: center; gap: 10px;">\n                        <span style="color: #02D28C; font-weight: 700; font-size: 1.125rem;">&#10003;</span>\n                        Full automation of cross-department workflows\n                    </li>\n                    <li style="padding: 10px 0; border-bottom: 1px solid #e2e8f0; color: #333; display: flex; align-items: center; gap: 10px;">\n                        <span style="color: #02D28C; font-weight: 700; font-size: 1.125rem;">&#10003;</span>\n                        Eliminated manual data re-entry between departments\n                    </li>\n                    <li style="padding: 10px 0; color: #333; display: flex; align-items: center; gap: 10px;">\n                        <span style="color: #02D28C; font-weight: 700; font-size: 1.125rem;">&#10003;</span>\n                        Single source of truth for all operational data\n                    </li>\n                </ul>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 5"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 5: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Detail 5: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-detail-section" id="case-taiyo" style="background:#F5F7FA">\n    <div class="cs-detail-inner">\n                <div class="cs-detail-header cs-animate">\n                    <div class="cs-detail-badge">Fasteners</div>\n                    <div class="cs-company-identity">\n                        <div class="cs-company-logo">\n                            <img src="data:image/jpeg;base64," alt="Taiyo Fastener Thailand logo" loading="lazy">\n                        </div>\n                        <div class="cs-company-info-block">\n                            <h2 class="cs-detail-company">Taiyo Fastener Thailand</h2>\n                            <p class="cs-company-desc">Japanese-standard fastener manufacturer · Bangpoo Industrial Estate, Samut Prakan</p>\n                            <p class="cs-company-desc" style="font-size: 0.8125rem; color: #888; margin-top: 2px;">Subsidiary of Taiyoseiko Corporation, Japan</p>\n                        </div>\n                    </div>\n                    <div class="cs-detail-products-used">\n                        <span class="cs-detail-product-tag">ERP</span>\n                        <span class="cs-detail-product-tag">WMS (sFLS)</span>\n                    </div>\n                    <div class="cs-detail-metric-hero">\n                        <span class="cs-detail-metric-value" style="font-size: 2rem;">Systems Unified</span>\n                    </div>\n                </div>\n    \n                <h3>The Challenge</h3>\n                <p>Japanese fastener manufacturer operating in Thailand with multiple disconnected systems. Material tracking errors caused production delays and customer delivery issues.</p>\n    \n                <h3>The Solution</h3>\n                <p>Deployed DigiWin ERP and WMS to replace fragmented systems with a single unified platform. Barcode-driven warehouse operations eliminated manual material tracking.</p>\n    \n                <h3>Results</h3>\n                <ul style="padding-left: 0; list-style: none;">\n                    <li style="padding: 10px 0; border-bottom: 1px solid #e2e8f0; color: #333; display: flex; align-items: center; gap: 10px;">\n                        <span style="color: #02D28C; font-weight: 700; font-size: 1.125rem;">&#10003;</span>\n                        Unified multiple legacy systems into one platform\n                    </li>\n                    <li style="padding: 10px 0; border-bottom: 1px solid #e2e8f0; color: #333; display: flex; align-items: center; gap: 10px;">\n                        <span style="color: #02D28C; font-weight: 700; font-size: 1.125rem;">&#10003;</span>\n                        Reduced material tracking errors\n                    </li>\n                    <li style="padding: 10px 0; color: #333; display: flex; align-items: center; gap: 10px;">\n                        <span style="color: #02D28C; font-weight: 700; font-size: 1.125rem;">&#10003;</span>\n                        Improved production scheduling accuracy\n                    </li>\n                </ul>\n    \n                \n                <div class="cs-callout cs-animate">\n                    <div class="cs-callout-title">Japanese Quality Standards, Thai Operations</div>\n                    <p>When a Japanese manufacturer with the world\'s strictest quality standards chose DigiWin for their Thailand operation, it wasn\'t because we were the cheapest option. Taiyo Fastener (a subsidiary of Japan\'s Taiyoseiko Corporation) needed a system that could meet Japanese-grade traceability and accuracy requirements — in a Thai manufacturing environment.</p>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Listed"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Listed: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Listed: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-listed-section">\n    <div class="cs-listed-inner">\n                <div class="cs-section-label">More Success Stories</div>\n                <h2 class="cs-section-title">Growing Every Quarter</h2>\n                <p class="cs-section-subtitle">Our Thailand case study library continues to expand. Contact us for references in your specific industry.</p>\n    \n                \n                <div class="cs-listed-grid">\n                    <div class="cs-listed-card cs-animate">\n                        <div class="cs-listed-logo">\n                            <img src="data:image/png;base64," 