\n                    </div>\n                    <div class="cs-placeholder-card cs-animate">\n                        <div class="cs-placeholder-icon">\n                            <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>\n                        </div>\n                        <p class="cs-placeholder-text">Food-grade compliance? We\'ve done it.</p>\n                        <a href="/demo/" class="cs-placeholder-cta">Contact for References →</a>\n                    </div>\n                    <div class="cs-placeholder-card cs-animate">\n                        <div class="cs-placeholder-icon">\n                            <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/><polyline points="10 9 9 9 8 9"/></svg>\n                        </div>\n                        <p class="cs-placeholder-text">Textile manufacturers — ask about production tracking results.</p>\n                        <a href="/demo/" class="cs-placeholder-cta">Contact for References →</a>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Insights"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Insights: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Cs Insights: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-insights-section">\n    <div class="cs-insights-inner">\n                <div class="cs-insights-stats">\n                    <div class="cs-animate">\n                        <div class="cs-insight-stat-value">75%</div>\n                        <div class="cs-insight-stat-label">Faster Month-End Closing</div>\n                    </div>\n                    <div class="cs-animate">\n                        <div class="cs-insight-stat-value">90-95%</div>\n                        <div class="cs-insight-stat-label">Stock Accuracy Achieved</div>\n                    </div>\n                    <div class="cs-animate">\n                        <div class="cs-insight-stat-value">+11pp</div>\n                        <div class="cs-insight-stat-label">Gross Profit Improvement</div>\n                    </div>\n                </div>\n                <div class="cs-insights-quote cs-animate">\n                    <p><strong>The pattern is clear:</strong> DigiWin\'s Thai customers consistently report two transformations — dramatically faster financial closing (from months to weeks) and stock accuracy that finally matches reality. These aren\'t aspirational targets. They\'re measured outcomes from factories operating in Thailand today.</p>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Want Results Like These?"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Want Results Like These?: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Want Results Like These?: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="cs-cta-section">\n    \n    \n    <div class="cs-cta-container">\n      <h2 class="cs-cta-title">Want Results Like These?</h2>\n      <p class="cs-cta-subtitle">Every factory is different. Tell us about yours and we’ll share relevant case studies from your industry.</p>\n      <div class="cs-cta-btn-row">\n        <a href="/demo/" class="cs-cta-btn cs-cta-btn--primary">Let’s Talk</a>\n        <a href="/products/" class="cs-cta-btn cs-cta-btn--ghost">Explore Products</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100749;

