INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100749, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === CS HERO (S1) === */\n/* TODO: Review and remap class selectors to use csh prefix */\n/* TODO: Add section container: .csh-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.cs-hero {\n            background: linear-gradient(165deg, #000432 0%, #000864 40%, #001080 100%);\n            padding: 140px 24px 80px;\n            position: relative;\n            overflow: hidden;\n            text-align: center;\n        }\n.cs-hero::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            pointer-events: none;\n        }\n.cs-hero-inner {\n            max-width: 800px;\n            margin: 0 auto;\n            position: relative;\n            z-index: 2;\n        }\n.cs-hero-badge {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            background: rgba(0, 175, 240, 0.15);\n            border: 1px solid rgba(0, 175, 240, 0.3);\n            padding: 8px 20px;\n            border-radius: 50px;\n            color: #00E6FF;\n            font-size: 11px;\n            font-weight: 500;\n            margin-bottom: 24px;\n            font-family: \'JetBrains Mono\', monospace;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n        }\n.cs-hero-badge::before {\n            content: \'\';\n            width: 8px;\n            height: 8px;\n            background: #00AFF0;\n            border-radius: 50%;\n            animation: pulse-dot 2s ease-in-out infinite;\n        }\n.cs-hero h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(2rem, 5vw, 3.25rem);\n            font-weight: 800;\n            color: #fff;\n            line-height: 1.15;\n            margin: 0 0 20px;\n        }\n.cs-hero-subtitle {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 1.125rem;\n            color: rgba(255, 255, 255, 0.85);\n            line-height: 1.6;\n            max-width: 640px;\n            margin: 0 auto 40px;\n        }\n.cs-hero-stats {\n            display: flex;\n            justify-content: center;\n            gap: 48px;\n            padding-top: 32px;\n            border-top: 1px solid rgba(255, 255, 255, 0.1);\n        }\n.cs-hero-stat-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 2rem;\n            font-weight: 800;\n            color: #00AFF0;\n        }\n.cs-hero-stat-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            color: rgba(255, 255, 255, 0.85);\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-top: 4px;\n        }\n@media (max-width: 640px) {\n            .cs-hero {\n                padding: 120px 20px 60px;\n            }\n            .cs-hero-stats {\n                flex-direction: column;\n                gap: 20px;\n            }\n            .cs-company-identity {\n                gap: 16px;\n            }\n            .cs-company-logo {\n                width: 90px;\n                height: 60px;\n                padding: 4px 6px;\n            }\n            .cs-listed-logo {\n                width: 52px;\n                height: 52px;\n                padding: 3px;\n            }\n            .cs-card-grid {\n                grid-template-columns: 1fr;\n            }\n            .cs-listed-grid {\n                grid-template-columns: 1fr;\n            }\n            .cs-placeholder-grid {\n                grid-template-columns: 1fr;\n            }\n            .cs-insights-stats {\n                grid-template-columns: 1fr;\n                gap: 24px;\n            }\n            .cs-detail-metric-hero {\n                flex-direction: column;\n                gap: 4px;\n            }\n            .cs-results-table {\n                font-size: 0.8125rem;\n            }\n            .cs-results-table thead th,\n            .cs-results-table tbody td {\n                padding: 10px 12px;\n            }\n        }\n@media (prefers-reduced-motion: reduce) {\n            .cs-hero-badge::before { animation: none; }\n            .cs-animate { opacity: 1; transform: none; transition: none; }\n        }\n\n/* TODO: PSEUDO-ELEMENTS using global classes (port manually) */\n/* .dw-grain-overlay::before{content:\'\';position:absolute;inset:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 256 256\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noise\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noise)\' opacity=\'0.5\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;animation:grain 8s steps(10) infinite;z-index:1} */\n\n.et_pb_section .cs-hero-subtitle {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.et_pb_section .cs-hero-stat-label {\n            line-height: 16px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .cs-hero-stat-value {\n            line-height: 51.2px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n/* === CS GRID (S2) === */\n/* TODO: Review and remap class selectors to use csg prefix */\n/* TODO: Add section container: .cs-grid-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.cs-grid-section {\n            background: #fff;\n            padding: 80px 24px 100px;\n        }\n.cs-grid-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n        }\n.cs-filters {\n            display: flex;\n            flex-wrap: wrap;\n            gap: 8px;\n            justify-content: center;\n            margin-bottom: 48px;\n        }\n.cs-filter-btn {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 12px;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            padding: 14px 20px;\n            min-height: 44px;\n            border-radius: 8px;\n            border: 1px solid #e2e8f0;\n            background: #F5F7FA;\n            color: #333;\n            cursor: pointer;\n            transition: all 0.3s ease;\n        }\n.cs-filter-btn:hover {\n            border-color: #00AFF0;\n            color: #00AFF0;\n        }\n.cs-filter-btn.active {\n            background: #006dac;\n            color: #fff;\n            border-color: #006dac;\n        }\n.cs-card-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 24px;\n        }\n.cs-card {\n            background: #fff;\n            border: 1px solid #e2e8f0;\n            border-radius: 16px;\n            padding: 32px;\n            transition: all 0.3s ease;\n            cursor: pointer;\n            text-decoration: none;\n            color: inherit;\n            display: block;\n        }\n.cs-card:hover {\n            border-color: #00AFF0;\n            box-shadow: 0 8px 30px rgba(0, 175, 240, 0.12);\n            transform: translateY(-2px);\n        }\n.cs-card-badge {\n            display: inline-block;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            padding: 4px 12px;\n            border-radius: 4px;\n            background: rgba(0, 175, 240, 0.1);\n            color: #00AFF0;\n            margin-bottom: 16px;\n        }\n.cs-card-company {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 1.25rem;\n            font-weight: 700;\n            color: #000864;\n            margin: 0 0 8px;\n        }\n.cs-card-summary {\n            font-size: 0.875rem;\n            color: #666;\n            line-height: 1.5;\n            margin: 0 0 20px;\n        }\n.cs-card-metric {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 2rem;\n            font-weight: 800;\n            color: #00AFF0;\n            margin: 0 0 4px;\n        }\n.cs-card-metric-label {\n            font-size: 0.8125rem;\n            color: #666;\n            margin: 0 0 16px;\n        }\n.cs-card-products {\n            display: flex;\n            flex-wrap: wrap;\n            gap: 6px;\n            margin-bottom: 20px;\n        }\n.cs-card-product-tag {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            padding: 4px 10px;\n            border-radius: 4px;\n            background: #F5F7FA;\n            color: #555;\n        }\n.cs-card-link {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 0.875rem;\n            font-weight: 600;\n            color: #00AFF0;\n            text-decoration: none;\n        }\n.cs-card-link::after {\n            content: \' →\';\n        }\n.cs-filter-btn:focus-visible {\n            outline: 3px solid #00AFF0;\n            outline-offset: 2px;\n        }\n.cs-card:focus-visible {\n            outline: 3px solid #00AFF0;\n            outline-offset: 3px;\n        }\n.cs-animate {\n            opacity: 1;\n            transform: none;\n        }\n@media (max-width: 1024px) {\n            .cs-card-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n            .cs-listed-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n            .cs-placeholder-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n            .cs-criteria-list {\n                grid-template-columns: 1fr;\n            }\n        }\n@media (max-width: 640px) {\n            .cs-hero {\n                padding: 120px 20px 60px;\n            }\n            .cs-hero-stats {\n                flex-direction: column;\n                gap: 20px;\n            }\n            .cs-company-identity {\n                gap: 16px;\n            }\n            .cs-company-logo {\n                width: 90px;\n                height: 60px;\n                padding: 4px 6px;\n            }\n            .cs-listed-logo {\n                width: 52px;\n                height: 52px;\n                padding: 3px;\n            }\n            .cs-card-grid {\n                grid-template-columns: 1fr;\n            }\n            .cs-listed-grid {\n                grid-template-columns: 1fr;\n            }\n            .cs-placeholder-grid {\n                grid-template-columns: 1fr;\n            }\n            .cs-insights-stats {\n                grid-template-columns: 1fr;\n                gap: 24px;\n            }\n            .cs-detail-metric-hero {\n                flex-direction: column;\n                gap: 4px;\n            }\n            .cs-results-table {\n                font-size: 0.8125rem;\n            }\n            .cs-results-table thead th,\n            .cs-results-table tbody td {\n                padding: 10px 12px;\n            }\n        }\n@media (prefers-reduced-motion: reduce) {\n            .cs-hero-badge::before { animation: none; }\n            .cs-animate { opacity: 1; transform: none; transition: none; }\n        }\n\n/* TODO: HOVER STATES using global classes (port manually) */\n/* .dw-nav-item.active .dw-nav-link svg,.dw-nav-item:hover .dw-nav-link svg{transform:rotate(180deg)} */\n/* TODO: PSEUDO-ELEMENTS using global classes (port manually) */\n/* .dw-nav-item.active .dw-nav-link::after{transform:scaleX(1)} */\n.mockup-nav-item.active{color:#00AFF0}\n.mockup-bar.active{opacity:1;background:#10b981}\n\n@media(prefers-reduced-motion:reduce){}\n\n.et_pb_section .cs-filter-btn {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.et_pb_section .cs-card {\n            line-height: 25.6px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .cs-card-badge {\n            line-height: 16px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .cs-card-summary {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.et_pb_section .cs-card-metric {\n            line-height: 38.4px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .cs-card-metric-label {\n            line-height: 20.8px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .cs-card-product-tag {\n            line-height: 16px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .cs-card-link {\n            line-height: 22.4px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .cs-card-company {\n            -webkit-font-smoothing: auto !important;\n        }\n/* === CS DETAIL (S3) === */\n/* TODO: Review and remap class selectors to use csd prefix */\n/* TODO: Add section container: .cs-detail-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.cs-detail-section {\n            padding: 80px 24px;\n            background: #F5F7FA;\n        }\n.cs-detail-inner {\n            max-width: 900px;\n            margin: 0 auto;\n        }\n.cs-detail-header {\n            margin-bottom: 40px;\n        }\n.cs-detail-badge {\n            display: inline-block;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            padding: 6px 16px;\n            border-radius: 6px;\n            background: rgba(0, 175, 240, 0.1);\n            color: #00AFF0;\n            margin-bottom: 16px;\n        }\n.cs-detail-company {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(1.5rem, 3vw, 2.25rem);\n            font-weight: 800;\n            color: #000864;\n            margin: 0 0 8px;\n        }\n.cs-detail-products-used {\n            display: flex;\n            flex-wrap: wrap;\n            gap: 8px;\n            margin-top: 12px;\n        }\n.cs-detail-product-tag {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            padding: 6px 14px;\n            border-radius: 6px;\n            background: #000864;\n            color: #fff;\n        }\n.cs-detail-metric-hero {\n            display: inline-flex;\n            align-items: baseline;\n            gap: 12px;\n            margin-top: 20px;\n        }\n.cs-detail-metric-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 3rem;\n            font-weight: 800;\n            color: #00AFF0;\n            line-height: 1;\n        }\n.cs-detail-metric-desc {\n       