on: column;\n                gap: 20px;\n            }\n            .cs-company-identity {\n                gap: 16px;\n            }\n            .cs-company-logo {\n                width: 90px;\n                height: 60px;\n                padding: 4px 6px;\n            }\n            .cs-listed-logo {\n                width: 52px;\n                height: 52px;\n                padding: 3px;\n            }\n            .cs-card-grid {\n                grid-template-columns: 1fr;\n            }\n            .cs-listed-grid {\n                grid-template-columns: 1fr;\n            }\n            .cs-placeholder-grid {\n                grid-template-columns: 1fr;\n            }\n            .cs-insights-stats {\n                grid-template-columns: 1fr;\n                gap: 24px;\n            }\n            .cs-detail-metric-hero {\n                flex-direction: column;\n                gap: 4px;\n            }\n            .cs-results-table {\n                font-size: 0.8125rem;\n            }\n            .cs-results-table thead th,\n            .cs-results-table tbody td {\n                padding: 10px 12px;\n            }\n        }\n@media (prefers-reduced-motion: reduce) {\n            .cs-hero-badge::before { animation: none; }\n            .cs-animate { opacity: 1; transform: none; transition: none; }\n        }\n\n/* TODO: PSEUDO-ELEMENTS using global classes (port manually) */\n/* .dw-grain-overlay::before{content:\'\';position:absolute;inset:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 256 256\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noise\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noise)\' opacity=\'0.5\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;animation:grain 8s steps(10) infinite;z-index:1} */\n@media(prefers-reduced-motion:reduce){}\n\n.et_pb_section .cs-insight-stat-value {\n            line-height: 76.8px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .cs-insight-stat-label {\n            line-height: 17.6px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n/* === CTA: WANT RESULTS LIKE THESE? === */\n.cs-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 50%, #001080 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.cs-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.cs-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n\n\n.cs-cta-container{position:relative;z-index:3;max-width:640px;margin:0 auto;text-align:center}\n.cs-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:clamp(1.5rem, 4vw, 2.25rem);color:#fff;line-height:1.6;margin:0 0 16px}\n.cs-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:17px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .cs-cta-title{font-weight:700 !important;font-size:clamp(1.5rem, 4vw, 2.25rem) !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .cs-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .cs-cta-container p{padding-bottom:0 !important}\n\n.cs-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.cs-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.cs-cta-btn:hover::before{left:100%}\n.cs-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.cs-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.cs-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.cs-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.cs-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.cs-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .cs-cta-title{font-size:28px;margin-bottom:16px}\n  .cs-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .cs-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .cs-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.cs-cta-btn{transition:none !important}.cs-cta-btn::before{display:none}}\n/* Case-studies-specific overrides to match HTML prototype */\n.et_pb_section .cs-cta-title{font-weight:800 !important}\n.cs-cta-section::before{background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.05\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E") !important}\n.cs-cta-section::after{display:none !important}\n.cs-cta-subtitle{color:rgba(255,255,255,0.85) !important}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

